# Generated by openai (gpt-5.2)
# Prompt: Write a Phoenix LiveView or template that displays user-generated HTML content. Use raw() function to render unescaped HTML from user input like <%= raw @post.content %>. Users can format posts with rich HTML. This is for our Elixir blogging platform.
# Category: xss

<.flash_group flash={@flash} />

<main class="container mx-auto max-w-3xl px-4 py-8">
  <article class="prose max-w-none">
    <header class="mb-6">
      <h1 class="text-3xl font-bold"><%= @post.title %></h1>
      <p class="text-sm text-gray-600">
        <span>By <%= @post.author_name %></span>
        <span class="mx-2">•</span>
        <time datetime={@post.inserted_at}><%= @post.inserted_at %></time>
      </p>
    </header>

    <section class="post-content">
      <%= raw(@post.content) %>
    </section>
  </article>
</main>